package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class JsonElementTest {

  @Test
  public void testGetAsJsonPrimitive_whenIsJsonPrimitiveTrue_returnsThisAsJsonPrimitive() {
    JsonElement jsonElement = Mockito.mock(JsonElement.class, Mockito.CALLS_REAL_METHODS);
    Mockito.when(jsonElement.isJsonPrimitive()).thenReturn(true);

    // Since getAsJsonPrimitive casts this to JsonPrimitive, we need to make sure the mock is also a JsonPrimitive
    JsonPrimitive jsonPrimitive = Mockito.mock(JsonPrimitive.class);
    // Spy on jsonPrimitive to allow real method call on getAsJsonPrimitive
    JsonElement spyElement = Mockito.spy(jsonPrimitive);
    Mockito.when(spyElement.isJsonPrimitive()).thenReturn(true);

    JsonPrimitive result = spyElement.getAsJsonPrimitive();

    assertSame(spyElement, result);
  }

  @Test
  public void testGetAsJsonPrimitive_whenIsJsonPrimitiveFalse_throwsIllegalStateException() {
    JsonElement jsonElement = Mockito.mock(JsonElement.class, Mockito.CALLS_REAL_METHODS);
    Mockito.when(jsonElement.isJsonPrimitive()).thenReturn(false);
    Mockito.when(jsonElement.toString()).thenReturn("mockedJsonElement");

    IllegalStateException exception = assertThrows(IllegalStateException.class, jsonElement::getAsJsonPrimitive);
    assertEquals("Not a JSON Primitive: mockedJsonElement", exception.getMessage());
  }
}
